        self.id = id
        self.patient_id = patient_id
        self.medication_code = medication_code

    @classmethod
    def from_fhir(cls, fhir_resource):
        if fhir_resource['resourceType'] == 'MedicationRequest':
            return cls(
                resource_type='MedicationRequest',
                id=fhir_resource.get('id'),
                patient_id=fhir_resource['subject']['reference'].split('/')[-1],
                medication_code=fhir_resource['medicationCodeableConcept']['coding'][0]['code']
            )
        elif fhir_resource['resourceType'] == 'MedicationStatement':
            return cls(
                resource_type='MedicationStatement',
                id=fhir_resource.get('id'),
                patient_id=fhir_resource['subject']['reference'].split('/')[-1],
                medication_code=fhir_resource['medicationCodeableConcept']['coding'][0]['code']
            )
        else:
            raise ValueError("Unsupported FHIR resource type")

    def to_dict(self):
        return {
            'resource_type': self.resource_type,
            'id': self.id,
            'patient_id': self.patient_id,
            'medication_code': self.medication_code
        }
