from datetime import datetime
import json

class CdsAlert:
    def __init__(self, severity_level: str, message: str, evidence_references: list, patient_id: str, medication_codes: list = [], allergy_codes: list = []):
        self.severity_level = severity_level
        self.message = message
        self.evidence_references = evidence_references
        self.patient_id = patient_id
        self.medication_codes = medication_codes
        self.allergy_codes = allergy_codes

    def to_dict(self) -> dict:
        return {
            "severity_level": self.severity_level,
            "message": self.message,
            "evidence_references": [{"url": ref["url"], "title": ref["title"]} for ref in self.evidence_references],
            "context": {
                "patient_id": self.patient_id,
                "medication_codes": self.medication_codes,
                "allergy_codes": self.allergy_codes,
                "timestamp": datetime.utcnow().isoformat()
            }
        }

    def to_json(self) -> str:
        return json.dumps(self.to_dict(), indent=2)

