        else:
            raise Exception("Failed to retrieve observation")

    def update_observation(self, observation_id: str, updated_data: dict, etag: str):
        headers = {
            'Authorization': f'Bearer {self.access_token}',
            'Content-Type': 'application/json',
            'If-Match': etag  # Use the ETag for optimistic concurrency control
        }

        response = requests.put(f"{self.base_url}/Observation/{observation_id}", json=updated_data, headers=headers)

        if response.status_code == 200:
            return response.json()
        elif response.status_code == 412:  # Precondition Failed (ETag mismatch)
            print("Precondition failed due to ETag mismatch. Resource has been updated by another user.")
            raise Exception("Resource has been concurrently modified")
        else:
            raise Exception(f"Failed to update observation: {response.text}")

