    for diastolic_obs in vital_signs_data['diastolic']:
        if not validate_observation(Observation(diastolic_obs)):
            raise ValueError("Diastolic BP observation does not meet required profile constraints")

    print(f"Vital signs data: {vital_signs_data}")
except ValueError as e:
