#### 2. Alert Enrichment Service
This service enriches raw alerts with severity levels and evidence references.

```python
from datetime import datetime, timezone

class CDSAlert:
    def __init__(self, message: str, raw_severity_level: str, evidence_references: list):
        self.message = message
        self.raw_severity_level = raw_severity_level
        self.evidence_references = evidence_references

    def to_dict(self) -> dict:
        return {
            "message": self.message,
            "severity_level": determine_severity_level(self.raw_severity_level),
            "evidence_references": self.evidence_references,
            "timestamp": datetime.now(timezone.utc).isoformat()
        }

def enrich_alerts(alerts):
    enriched_alerts = []

    for alert in alerts:
        if 'raw_severity_level' in alert and 'message' in alert:
            enriched_alert = CDSAlert(
                message=alert['message'],
                raw_severity_level=alert['raw_severity_level'],
                evidence_references=["http://example.com/guideline/1", "http://example.com/guideline/2"]
            )
            enriched_alerts.append(enriched_alert.to_dict())

    return enriched_alerts

def determine_severity_level(raw_severity_level):
    severity_levels = {
        'WARNING': 'WARNING',
        'CRITICAL': 'CRITICAL'
    }

    return severity_levels.get(raw_severity_level, 'INFO')

# Example usage
alerts = generate_alerts('12345')
enriched_alerts = enrich_alerts(alerts)
print(enriched_alerts)
```

